mapper.select:
select 
from ai_chat_session
where id = #{id}
  and student_id = #{studentId}
  and status = 'ACTIVE'
limit 1

mapper.update:
update ai_chat_session
set updated_at = now()
where id = #{id}
  and student_id = #{studentId}
  and status = 'ACTIVE'

update ai_chat_session
set status = 'DELETED',
    updated_at = now()
where id = #{id}
  and student_id = #{studentId}
  and status = 'ACTIVE'
